public class DatabaseOptions
{
    public const string SectionName = "Database";

    [Required, MinLength(10)]
    public string ConnectionString { get; init; } = "";

    [Range(1, 100)]
    public int MaxPoolSize { get; init; } = 20;

    [Range(1, 300)]
    public int CommandTimeoutSeconds { get; init; } = 30;
}

// Registration với validation và fail-fast
builder.Services
    .AddOptions<DatabaseOptions>()
    .BindConfiguration(DatabaseOptions.SectionName)
    .ValidateDataAnnotations()
    .ValidateOnStart(); // throw ở startup nếu invalid

// Custom validation logic
builder.Services
    .AddOptions<SmtpOptions>()
    .BindConfiguration("Smtp")
    .Validate(opt => !(opt.EnableTls && opt.Port != 587),
        "TLS yêu cầu port 587")
    .ValidateOnStart();

// Usage
public class OrderService(IOptions<DatabaseOptions> dbOpts)
{
    private readonly DatabaseOptions _db = dbOpts.Value; // cached, singleton
}

// Hot-reload với IOptionsMonitor
public class FeatureFlagService(IOptionsMonitor<FeatureFlags> monitor)
{
    public bool IsEnabled(string flag) =>
        monitor.CurrentValue.EnabledFlags.Contains(flag);
}
